example.code:
user = {"name": "Alice", "role": "admin"}

# Quote reuse in expression (pre-3.12 required different quote type)
greeting = f"Hello {user['name']}"

# Multiline expression
summary = f"User: {
    user['name'].title()
} ({user['role']})"

# Nested f-strings
price_fmt = f"{f'{price:.2f}'}"
